const respuesta = $input.first().json.output || "";
const htmlMatch = respuesta.match(/\[HTML\]([\s\S]*?)\[\/HTML\]/i);

let tituloDetectado = respuesta.split('[HTML]')[0].replace(/Aquí tienes el|el reporte solicitado:|:|\[/gi, '').trim();
if (!tituloDetectado || tituloDetectado.length > 50) tituloDetectado = "Reporte del Sistema";

const fechaSolo = new Date().toLocaleDateString('es-PE', { 
    timeZone: 'America/Lima',
    day: '2-digit', 
    month: '2-digit', 
    year: 'numeric' 
});

let htmlFinal = "";

if (htmlMatch) {
    let contenido = htmlMatch[1].trim();
    contenido = contenido.split('</td>').map(col => {
        if (col.includes('(Cant:')) {
            return col.replace(/, /g, '<br>• ').replace('<td>', '<td>• ');
        }
        return col;
    }).join('</td>');

    htmlFinal = `
    <!DOCTYPE html>
    <html lang="es">
    <head>
        <meta charset="UTF-8">
        <style>
            body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; color: #333; background-color: #fff; }

            /* Encabezado */
            .header-container { text-align: center; border-bottom: 3px solid #1a1a2e; margin-bottom: 30px; padding-bottom: 10px; }
            .report-title { color: #1a1a2e; font-size: 22px; text-transform: uppercase; letter-spacing: 2px; margin: 0; }
            .report-date { font-size: 13px; color: #666; margin-top: 5px; font-weight: bold; }

            /* Tabla Principal */
            table { width: 100%; border-collapse: collapse; margin-top: 10px; table-layout: auto; }
            th { background: #1a1a2e; color: #ffffff; padding: 10px 5px; text-align: center; font-size: 10px; text-transform: uppercase; border: 1px solid #1a1a2e; }
            td { padding: 8px 5px; border: 1px solid #eeeeee; font-size: 10px; vertical-align: top; color: #444; }

            /* Filas intercaladas */
            tr:nth-child(even) { background: #f8f9fa; }

            /* Estilo específico para la columna de productos (la última) */
            td:last-child { 
                line-height: 1.4; 
                color: #222; 
                white-space: nowrap; /* Evita que el texto se amontone si hay espacio */
            }
        </style>
    </head>
    <body>
        <div class="header-container">
            <h1 class="report-title">${tituloDetectado.toUpperCase()}</h1>
            <div class="report-date">FECHA: ${fechaSolo}</div>
        </div>
        ${contenido}
    </body>
    </html>`;
} else {
    htmlFinal = `<!DOCTYPE html><html><body style="font-family:sans-serif; padding:20px;">${respuesta.replace(/\n/g, '<br>')}</body></html>`;
}

return {
    html_para_pdf: htmlFinal,
    tiene_formato: !!htmlMatch
};
